                  setMinPrice(''); setMaxPrice(''); setM2Min(''); setM2Max(''); setM2NetMin(''); setM2NetMax('');
                  setSelectedRooms([]); setSelectedFloors([]); setSelectedHeating([]); setSelectedProvince('Tüm İller'); setSelectedDistrict('');
                  setSelectedWho([]); setSelectedUsage([]); setSelectedDeeds([]); setActiveDropdown(null);
                  setFeatures({ ebeveynBanyo: false, asansor: false, otopark: false, esyali: false, balkon: false, siteIcirisi: false, krediyeUygun: false, takasli: false, amerikanMutfak: false });
